import{_ as e,o as l,c as r,a2 as a}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"黃豆追蹤日誌 — 2026-05-06（週三）","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-06.md","filePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-06.md"}'),n={name:"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-06.md"};function i(d,t,o,s,g,h){return l(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="黃豆追蹤日誌-—-2026-05-06-週三" tabindex="-1">黃豆追蹤日誌 — 2026-05-06（週三） <a class="header-anchor" href="#黃豆追蹤日誌-—-2026-05-06-週三" aria-label="Permalink to &quot;黃豆追蹤日誌 — 2026-05-06（週三）&quot;">​</a></h1><blockquote><p>📅 報告日期：2026-05-06（TST 05:00） 📡 資料截止：2026-05-05 17:00 EDT</p></blockquote><hr><h2 id="🫘-cbot-黃豆期貨價格" tabindex="-1">🫘 CBOT 黃豆期貨價格 <a class="header-anchor" href="#🫘-cbot-黃豆期貨價格" aria-label="Permalink to &quot;🫘 CBOT 黃豆期貨價格&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">指標</th><th style="text-align:right;">數據</th><th style="text-align:left;">備註</th><th style="text-align:left;">查詢時間 (TST)</th></tr></thead><tbody><tr><td style="text-align:left;">CBOT 黃豆近月合約（5/1 收盤）</td><td style="text-align:right;">$12.03/bu</td><td style="text-align:left;">+$0.25/週</td><td style="text-align:left;">05-01</td></tr><tr><td style="text-align:left;">CBOT 黃豆（5/5 日內）</td><td style="text-align:right;">下跌 3-5 ¢/bu</td><td style="text-align:left;">技術性回檔+農民賣壓</td><td style="text-align:left;">05-05</td></tr><tr><td style="text-align:left;">CBOT 豆油（7月）</td><td style="text-align:right;">上漲 1.8%</td><td style="text-align:left;">創合約新高</td><td style="text-align:left;">05-05</td></tr><tr><td style="text-align:left;">CBOT 玉米近月（5/1 收盤）</td><td style="text-align:right;">$4.80/bu</td><td style="text-align:left;">13 個月新高</td><td style="text-align:left;">05-01</td></tr></tbody></table><p><strong>查詢來源：</strong></p><ol><li>Farm Forum (2026-05-05): CBOT soybean $12.03 (5/1 close), +$1.50 YTD</li><li>MarketsFarm (2026-05-05): soybeans down 3-5 cents/bu on Tuesday</li><li>Savera International/Twitter (2026-05-05): CBOT soyoil JUL up 1.8%, fresh contract highs</li></ol><hr><h2 id="📋-8-項追蹤指標" tabindex="-1">📋 8 項追蹤指標 <a class="header-anchor" href="#📋-8-項追蹤指標" aria-label="Permalink to &quot;📋 8 項追蹤指標&quot;">​</a></h2><h3 id="_1-usda-種植進度報告-每週" tabindex="-1">1. USDA 種植進度報告（每週） <a class="header-anchor" href="#_1-usda-種植進度報告-每週" aria-label="Permalink to &quot;1. USDA 種植進度報告（每週）&quot;">​</a></h3><ul><li><strong>最新數據</strong>：本週無 USDA 種植進度更新（上週報告為 4/28 發布）</li><li><strong>預計下次更新</strong>：2026-05-12（USDA 週一報告）</li><li><strong>狀態</strong>：⚠️ 待更新</li></ul><h3 id="_2-巴西供應-收割-出口-豐收" tabindex="-1">2. 巴西供應（收割 + 出口 + 豐收） <a class="header-anchor" href="#_2-巴西供應-收割-出口-豐收" aria-label="Permalink to &quot;2. 巴西供應（收割 + 出口 + 豐收）&quot;">​</a></h3><ul><li><strong>收割進度</strong>：截至 3 月底約 74-75%（落後去年同期 81-82%）</li><li><strong>產量預估</strong>：<strong>1.8 億噸創歷史紀錄</strong>（Cepea 5/5 確認）</li><li><strong>出口</strong>：Q1 2026 出口量較 2025 Q1 增加 5.92%</li><li><strong>巴西現貨</strong>：大豆價格堅挺，榨利創 2024 年 8 月以來最高</li><li><strong>運費上漲</strong>：中西部主要路線運費月增 10-35%</li><li><strong>變化</strong>：🟢 巴西豐收壓力被強勁需求吸收，價格未崩盤</li></ul><h3 id="_3-尿素價格-多單訊號" tabindex="-1">3. 尿素價格 + 多單訊號 <a class="header-anchor" href="#_3-尿素價格-多單訊號" aria-label="Permalink to &quot;3. 尿素價格 + 多單訊號&quot;">​</a></h3><ul><li><strong>本週無尿素專項更新</strong></li><li><strong>狀態</strong>：⚠️ 待補充（下週追蹤）</li></ul><h3 id="_4-荷莫茲海峽通航狀態-即時" tabindex="-1">4. 荷莫茲海峽通航狀態（即時） <a class="header-anchor" href="#_4-荷莫茲海峽通航狀態-即時" aria-label="Permalink to &quot;4. 荷莫茲海峽通航狀態（即時）&quot;">​</a></h3><ul><li><strong>最新狀態</strong>：海峽實質關閉近兩個月</li><li><strong>5/5 發展</strong>：美伊在海峽交火，兩艘美國商船在軍事護航下通過</li><li><strong>Hegseth</strong>：稱停火仍有效，「Project Freedom」護航計畫持續</li><li><strong>風險</strong>：若衝突升級，中東糧食運輸將受嚴重影響</li><li><strong>變化</strong>：🔴 緊張升級但暫未中斷糧食運輸</li></ul><h3 id="_5-中美貿易-中國進口" tabindex="-1">5. 中美貿易 + 中國進口 <a class="header-anchor" href="#_5-中美貿易-中國進口" aria-label="Permalink to &quot;5. 中美貿易 + 中國進口&quot;">​</a></h3><ul><li><strong>中國五一假期</strong>：5/1-5 停止新聞更新（Mysteel 確認）</li><li><strong>USDA 出口銷售</strong>：最新一週黃豆出口 2,560 萬蒲式耳（舊+新作）</li><li><strong>印尼政策</strong>：5/8 起將要求大豆進口許可證</li><li><strong>變化</strong>：🟡 假期影響暫緩，但進口需求結構性支撐仍在</li></ul><h3 id="_6-天然氣價格" tabindex="-1">6. 天然氣價格 <a class="header-anchor" href="#_6-天然氣價格" aria-label="Permalink to &quot;6. 天然氣價格&quot;">​</a></h3><ul><li><strong>Henry Hub 現貨</strong>：$2.72/MMBtu（FRED 4/27）</li><li><strong>天然氣期貨（7月）</strong>：$3.131（-0.028），低檔盤整</li><li><strong>全球基準</strong>：TTF/JKM 維持大幅溢價</li><li><strong>影響</strong>：低天然氣價格有利氮肥（尿素）生產成本，間接利多黃豆種植利潤</li><li><strong>變化</strong>：🟡 低檔穩定，無重大變化</li></ul><h3 id="_7-聖嬰-拉尼娜氣候風險-每季" tabindex="-1">7. 聖嬰/拉尼娜氣候風險（每季） <a class="header-anchor" href="#_7-聖嬰-拉尼娜氣候風險-每季" aria-label="Permalink to &quot;7. 聖嬰/拉尼娜氣候風險（每季）&quot;">​</a></h3><ul><li><strong>最新預測</strong>：La Niña 已結束，多機構預測 <strong>2026 年底轉入 El Niño</strong></li><li><strong>影響評估</strong>：El Niño 通常利多全球大豆產量（+2-5%），但利空玉米/小麥/稻米</li><li><strong>風險</strong>：若 El Niño 在北半球夏季形成，可能影響美國中西部降雨模式</li><li><strong>變化</strong>：🟡 氣候轉換中，長期需密切觀察</li></ul><h3 id="_8-cbot-價格區間-每日" tabindex="-1">8. CBOT 價格區間（每日） <a class="header-anchor" href="#_8-cbot-價格區間-每日" aria-label="Permalink to &quot;8. CBOT 價格區間（每日）&quot;">​</a></h3><ul><li><strong>5/1 收盤</strong>：$12.03/bu</li><li><strong>5/5 日內</strong>：下跌 3-5 ¢/bu（技術性回檔+農民賣壓）</li><li><strong>估算 5/5 收盤</strong>：約 $11.98-$12.00/bu</li><li><strong>YTD 漲幅</strong>：+$1.50/bu（自年初起算）</li><li><strong>與歷史比較</strong>：高於 2025 同期 $10.50，低於 2023 $14.99</li><li><strong>變化</strong>：🟡 小幅回檔，區間整理</li></ul><hr><h2 id="📰-即時新聞-5-條" tabindex="-1">📰 即時新聞（5 條） <a class="header-anchor" href="#📰-即時新聞-5-條" aria-label="Permalink to &quot;📰 即時新聞（5 條）&quot;">​</a></h2><ol><li><p><strong>Cepea-Brazil (5/5)</strong>：巴西大豆價格堅挺，創紀錄 1.8 億噸豐收被強勁需求吸收，榨利創 2024 年 8 月以來最高。中東衝突推高油價，帶動巴西生物柴油競爭力，大豆油需求上升。</p></li><li><p><strong>TradingView/Reuters (5/5)</strong>：CBOT 黃豆期貨技術性回檔，農民趁漲勢賣壓湧現，油價下跌連帶拖累。分析師指「連續兩日上漲後獲利了結」。</p></li><li><p><strong>Farm Forum (5/5)</strong>：2026 CBOT 黃豆期貨已超越 2025 同期 $10.50 和 2024 $11.63，但仍低於 2023 $14.99。玉米近月 $4.80 創 13 個月新高。</p></li><li><p><strong>USDA FAS (5/5)</strong>：<strong>印尼將於 5/8 起要求大豆進口許可證</strong>，可能影響東南亞大豆貿易格局。USDA 週出口銷售報告將於 5/8 發布。</p></li><li><p><strong>Savera International (5/5)</strong>：CBOT 豆油 7 月合約上漲 1.8% 創合約新高，受生物柴油需求支撐。BMD（馬來西亞棕櫚油）同步上漲。</p></li></ol><hr><h2 id="📊-供需結構摘要" tabindex="-1">📊 供需結構摘要 <a class="header-anchor" href="#📊-供需結構摘要" aria-label="Permalink to &quot;📊 供需結構摘要&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">因素</th><th style="text-align:center;">方向</th><th style="text-align:center;">影響程度</th></tr></thead><tbody><tr><td style="text-align:left;">巴西豐收 1.8 億噸</td><td style="text-align:center;">⬇️ 利空</td><td style="text-align:center;">⭐⭐⭐</td></tr><tr><td style="text-align:left;">強勁壓榨需求</td><td style="text-align:center;">⬆️ 利多</td><td style="text-align:center;">⭐⭐⭐</td></tr><tr><td style="text-align:left;">生物柴油（油價推升）</td><td style="text-align:center;">⬆️ 利多</td><td style="text-align:center;">⭐⭐</td></tr><tr><td style="text-align:left;">中東地緣風險</td><td style="text-align:center;">⬆️ 利多</td><td style="text-align:center;">⭐⭐</td></tr><tr><td style="text-align:left;">印尼進口許可證</td><td style="text-align:center;">⬇️ 利空</td><td style="text-align:center;">⭐</td></tr><tr><td style="text-align:left;">El Niño 潛在轉換</td><td style="text-align:center;">⬆️ 利多</td><td style="text-align:center;">⭐（長期）</td></tr><tr><td style="text-align:left;">低天然氣/氮肥成本</td><td style="text-align:center;">⬆️ 利多</td><td style="text-align:center;">⭐</td></tr></tbody></table><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>來源</th><th>日期</th><th>內容</th></tr></thead><tbody><tr><td>1</td><td>Cepea-Brazil</td><td>2026-05-05</td><td>Brazil record crop 180M tons, firm prices</td></tr><tr><td>2</td><td>Farm Forum</td><td>2026-05-05</td><td>CBOT soybean $12.03 (5/1), corn $4.80</td></tr><tr><td>3</td><td>MarketsFarm</td><td>2026-05-05</td><td>Soybeans down 3-5 cents/bu</td></tr><tr><td>4</td><td>TradingView/Reuters</td><td>2026-05-05</td><td>Technical selloff, farmer selling</td></tr><tr><td>5</td><td>Savera International</td><td>2026-05-05</td><td>CBOT soyoil JUL up 1.8% contract high</td></tr><tr><td>6</td><td>USDA FAS</td><td>2026-05-05</td><td>Indonesia import license 5/8</td></tr><tr><td>7</td><td>Mysteel</td><td>2026-05-05</td><td>China May Day holiday, no updates 5/1-5</td></tr><tr><td>8</td><td>FRED</td><td>2026-04-27</td><td>Henry Hub $2.72</td></tr><tr><td>9</td><td>MarketWatch</td><td>2026-05-05</td><td>NG Jul $3.131</td></tr><tr><td>10</td><td>Reuters/SAWS/IRI</td><td>2026-04-24</td><td>El Niño 2026-27 projections</td></tr></tbody></table>',34)])])}const b=e(n,[["render",i]]);export{u as __pageData,b as default};
